import React from 'react';
import { View, TouchableOpacity, Text, StyleSheet } from 'react-native';

interface Props {
  onZoomIn: () => void;
  onZoomOut: () => void;
  onReset: () => void;
}

export default function ZoomControls({ onZoomIn, onZoomOut, onReset }: Props) {
  return (
    <View style={styles.container}>
      <TouchableOpacity onPress={onZoomIn} style={styles.btn} activeOpacity={0.7}>
        <Text style={styles.btnText}>+</Text>
      </TouchableOpacity>
      <TouchableOpacity onPress={onZoomOut} style={styles.btn} activeOpacity={0.7}>
        <Text style={styles.btnText}>−</Text>
      </TouchableOpacity>
      <TouchableOpacity onPress={onReset} style={styles.btn} activeOpacity={0.7}>
        <Text style={[styles.btnText, { fontSize: 12, fontWeight: '700' }]}>R</Text>
      </TouchableOpacity>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    position: 'absolute',
    top: 12,
    right: 12,
    gap: 6,
  },
  btn: {
    width: 38,
    height: 38,
    backgroundColor: 'rgba(30,27,75,0.95)',
    borderWidth: 1,
    borderColor: '#3730a3',
    borderRadius: 10,
    alignItems: 'center',
    justifyContent: 'center',
  },
  btnText: {
    color: '#a78bfa',
    fontSize: 20,
    lineHeight: 24,
  },
});