import React, { useRef, useEffect, useState, useCallback } from 'react';
import { View, Text, StyleSheet, PanResponder, LayoutChangeEvent } from 'react-native';
import { Canvas, useCanvasRef, Skia, Path, Paint } from '@shopify/react-native-skia';
import { Equation, ViewRange, plotEquation, mathToPixelX, mathToPixelY, pixelToMathX, computeGridLines } from '@mathgraph/core';
import ZoomControls from './ZoomControls';

interface ProbeValue {
  expr: string;
  color: string;
  mathY: number;
  dotPy: number;
}

interface Props {
  equations: Equation[];
  view: ViewRange;
  onZoomIn: () => void;
  onZoomOut: () => void;
  onReset: () => void;
}

export default function GraphCanvas({ equations, view, onZoomIn, onZoomOut, onReset }: Props) {
  const [size, setSize] = useState({ width: 0, height: 380 });
  const [probe, setProbe] = useState<{ px: number; mathX: number; values: ProbeValue[] } | null>(null);
  const probeTimeout = useRef<ReturnType<typeof setTimeout> | null>(null);

  const W = size.width;
  const H = size.height;

  function computeProbe(touchX: number) {
    if (!W) return;
    const cx = W / 2;
    const cy = H / 2;
    const mathX = pixelToMathX(touchX, view, W);
    const values: ProbeValue[] = equations.map(eq => {
      const result = plotEquation(eq.expression, view);
      if (result.hasError || !result.points.length) return null;
      const nearest = result.points.reduce((best, pt) => {
        return Math.abs(pt.x - mathX) < Math.abs(best.x - mathX) ? pt : best;
      });
      if (isNaN(nearest.y) || !isFinite(nearest.y)) return null;
      return {
        expr: eq.expression,
        color: eq.color,
        mathY: nearest.y,
        dotPy: mathToPixelY(nearest.y, view, H),
      };
    }).filter(Boolean) as ProbeValue[];
    setProbe({ px: touchX, mathX, values });
  }

  const panResponder = useRef(
    PanResponder.create({
      onStartShouldSetPanResponder: () => true,
      onMoveShouldSetPanResponder: () => true,
      onPanResponderGrant: (e) => {
        if (probeTimeout.current) clearTimeout(probeTimeout.current);
        computeProbe(e.nativeEvent.locationX);
      },
      onPanResponderMove: (e, gs) => {
        if (probeTimeout.current) clearTimeout(probeTimeout.current);
        // If mostly horizontal movement treat as probe, vertical as scroll
        computeProbe(e.nativeEvent.locationX);
      },
      onPanResponderRelease: () => {
        probeTimeout.current = setTimeout(() => setProbe(null), 1800);
      },
    })
  ).current;

  // Draw grid, axes, equations, and probe on a plain View + Canvas
  const drawLines = () => {
    if (!W) return null;
    const cx = W / 2;
    const cy = H / 2;
    const xLines = computeGridLines(view.xMin, view.xMax, W, 'x');
    const yLines = computeGridLines(view.yMin, view.yMax, H, 'y');

    return (
      <>
        {/* Grid */}
        {xLines.filter(l => !l.isAxis).map((l, i) => (
          <View key={'gx' + i} style={[styles.gridLine, { left: l.position, top: 0, width: 1, height: H, backgroundColor: 'rgba(124,58,237,0.1)' }]} />
        ))}
        {yLines.filter(l => !l.isAxis).map((l, i) => (
          <View key={'gy' + i} style={[styles.gridLine, { top: l.position, left: 0, height: 1, width: W, backgroundColor: 'rgba(124,58,237,0.1)' }]} />
        ))}
        {/* Axes */}
        <View style={[styles.gridLine, { top: Math.min(Math.max(mathToPixelY(0, view, H), 0), H), left: 0, height: 1.5, width: W, backgroundColor: 'rgba(124,58,237,0.45)' }]} />
        <View style={[styles.gridLine, { left: Math.min(Math.max(mathToPixelX(0, view, W), 0), W), top: 0, width: 1.5, height: H, backgroundColor: 'rgba(124,58,237,0.45)' }]} />
      </>
    );
  };

  const onLayout = (e: LayoutChangeEvent) => {
    const { width, height } = e.nativeEvent.layout;
    setSize({ width, height: height || 380 });
  };

  const tooltipLeft = probe && probe.px > W * 0.6 ? probe.px - 165 : (probe?.px ?? 0) + 14;

  return (
    <View style={styles.wrapper}>
      <View
        style={styles.graphArea}
        onLayout={onLayout}
        {...panResponder.panHandlers}
      >
        {/* Background */}
        <View style={[StyleSheet.absoluteFill, { backgroundColor: '#0d0f1e', borderRadius: 12 }]} />

        {/* Grid & Axes */}
        {drawLines()}

        {/* Probe crosshair */}
        {probe && (
          <View style={[styles.crosshair, { left: probe.px }]} />
        )}

        {/* Probe dots */}
        {probe?.values.map((v, i) => (
          v.dotPy > 0 && v.dotPy < H ? (
            <View key={i}>
              {/* Glow ring */}
              <View style={[styles.dotGlow, { left: probe.px - 9, top: v.dotPy - 9, backgroundColor: v.color + '22' }]} />
              {/* Main dot */}
              <View style={[styles.dot, { left: probe.px - 5.5, top: v.dotPy - 5.5, backgroundColor: v.color }]} />
              {/* White inner */}
              <View style={[styles.dotInner, { left: probe.px - 2, top: v.dotPy - 2 }]} />
            </View>
          ) : null
        ))}

        {/* Equations — SVG-like paths via Canvas */}
        <View style={StyleSheet.absoluteFill} pointerEvents="none">
          {W > 0 && equations.map(eq => {
            const result = plotEquation(eq.expression, view);
            if (result.hasError || !result.points.length) return null;
            return (
              <EquationPath key={eq.id} points={result.points} view={view} color={eq.color} W={W} H={H} />
            );
          })}
        </View>

        {/* Tooltip */}
        {probe && probe.values.length > 0 && (
          <View style={[styles.tooltip, { left: tooltipLeft, top: 14 }]}>
            <Text style={styles.tipX}>x = {probe.mathX.toFixed(3)}</Text>
            {probe.values.map((v, i) => (
              <View key={i} style={styles.tipRow}>
                <View style={[styles.tipDot, { backgroundColor: v.color }]} />
                <Text style={styles.tipExpr}>{v.expr}</Text>
                <Text style={styles.tipVal}>{v.mathY.toFixed(3)}</Text>
              </View>
            ))}
          </View>
        )}

        <ZoomControls onZoomIn={onZoomIn} onZoomOut={onZoomOut} onReset={onReset} />
      </View>
    </View>
  );
}

// Sub-component to draw a single equation as SVG polyline using React Native SVG
function EquationPath({ points, view, color, W, H }: { points: any[]; view: ViewRange; color: string; W: number; H: number }) {
  const Svg = require('react-native-svg').Svg;
  const Polyline = require('react-native-svg').Polyline;

  const segments: string[][] = [];
  let current: string[] = [];

  points.forEach(pt => {
    if (isNaN(pt.y) || !isFinite(pt.y)) { if (current.length) { segments.push(current); current = []; } return; }
    const px = mathToPixelX(pt.x, view, W);
    const py = mathToPixelY(pt.y, view, H);
    if (py < -H * 2 || py > H * 3) { if (current.length) { segments.push(current); current = []; } return; }
    current.push(`${px.toFixed(1)},${py.toFixed(1)}`);
  });
  if (current.length) segments.push(current);

  return (
    <Svg width={W} height={H} style={StyleSheet.absoluteFill}>
      {segments.map((seg, i) => (
        <Polyline key={i} points={seg.join(' ')} stroke={color} strokeWidth="2.2" fill="none" strokeLinejoin="round" strokeLinecap="round" />
      ))}
    </Svg>
  );
}

