import React from 'react';
import { View, ScrollView, TouchableOpacity, Text, StyleSheet } from 'react-native';
import { Equation } from '@mathgraph/core';

interface Props {
  equations: Equation[];
  onRemove: (id: string) => void;
}

export default function EquationTags({ equations, onRemove }: Props) {
  if (equations.length === 0) return null;

  return (
    <ScrollView
      horizontal
      showsHorizontalScrollIndicator={false}
      contentContainerStyle={styles.container}
    >
      {equations.map(eq => (
        <View
          key={eq.id}
          style={[
            styles.tag,
            { backgroundColor: eq.color + '20', borderColor: eq.color + '55' },
          ]}
        >
          <View style={[styles.dot, { backgroundColor: eq.color }]} />
          <Text style={[styles.expr, { color: eq.color }]}>{eq.expression}</Text>
          <TouchableOpacity
            onPress={() => onRemove(eq.id)}
            hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
          >
            <Text style={[styles.remove, { color: eq.color }]}>✕</Text>
          </TouchableOpacity>
        </View>
      ))}
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    paddingHorizontal: 14,
    paddingVertical: 8,
    gap: 8,
  },
  tag: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 6,
    paddingLeft: 10,
    paddingRight: 8,
    paddingVertical: 6,
    borderWidth: 1,
    borderRadius: 20,
  },
  dot: {
    width: 7,
    height: 7,
    borderRadius: 4,
  },
  expr: {
    fontSize: 13,
    fontFamily: 'monospace',
  },
  remove: {
    fontSize: 14,
    lineHeight: 16,
    opacity: 0.65,
  },
});